// Get first item from webhook
const item = $input.all()[0];

// Handle both cases: with body or without
const surveyData = item.json.body ?? item.json;

// Extract team members
const teamMembers = surveyData.teamMembers;

// Validate input
if (!Array.isArray(teamMembers) || teamMembers.length === 0) {
  return [
    {
      json: {
        error: 'teamMembers is missing or not an array',
        got: surveyData,
      },
    },
  ];
}

// -------- Vote counting --------

// Count date votes
const dateVotes = {};
teamMembers.forEach(member => {
  const date = member.preferredDate;
  if (!date) return;
  dateVotes[date] = (dateVotes[date] || 0) + 1;
});

// Count time votes
const timeVotes = {};
teamMembers.forEach(member => {
  const time = member.preferredTime;
  if (!time) return;
  timeVotes[time] = (timeVotes[time] || 0) + 1;
});

// Validate votes
if (Object.keys(dateVotes).length === 0 || Object.keys(timeVotes).length === 0) {
  return [
    {
      json: {
        error: 'No valid preferredDate or preferredTime found',
        got: teamMembers,
      },
    },
  ];
}

// Pick winning date
const winningDate = Object.keys(dateVotes).reduce((a, b) =>
  dateVotes[a] >= dateVotes[b] ? a : b
);

// Pick winning time
const winningTime = Object.keys(timeVotes).reduce((a, b) =>
  timeVotes[a] >= timeVotes[b] ? a : b
);

// Calculate agreement percentages
const totalVotes = teamMembers.length;
const datePercentage = Math.round((dateVotes[winningDate] / totalVotes) * 100);
const timePercentage = Math.round((timeVotes[winningTime] / totalVotes) * 100);

// Return final result
return [
  {
    json: {
      tripId: surveyData.tripId,
      fromCity: surveyData.fromCity,
      toCity: surveyData.toCity,
      recommendedDate: winningDate,
      recommendedTime: winningTime,
      analysis: {
        dateVotes,
        timeVotes,
        dateConsensus: `${datePercentage}% agreement`,
        timeConsensus: `${timePercentage}% agreement`,
      },
      totalParticipants: totalVotes,
    },
  },
];

const recommendation = $input.all()[0].json;

// Simulated flight database
const flightDatabase = [
  {
    flightId: "SV101",
    from: "Riyadh",
    to: "Dubai",
    date: "2025-12-15",
    departureTime: "08:00",
    arrivalTime: "10:30",
    timeCategory: "morning",
    price: 850,
    seats: 45
  },
  {
    flightId: "EK202",
    from: "Riyadh",
    to: "Dubai",
    date: "2025-12-15",
    departureTime: "14:00",
    arrivalTime: "16:30",
    timeCategory: "afternoon",
    price: 920,
    seats: 30
  },
  {
    flightId: "SV103",
    from: "Riyadh",
    to: "Dubai",
    date: "2025-12-16",
    departureTime: "09:30",
    arrivalTime: "12:00",
    timeCategory: "morning",
    price: 870,
    seats: 50
  },
  {
    flightId: "FZ305",
    from: "Riyadh",
    to: "Dubai",
    date: "2025-12-15",
    departureTime: "06:30",
    arrivalTime: "09:00",
    timeCategory: "morning",
    price: 750,
    seats: 25
  }
];

// Filter flights matching route, date, and time preference
const matchedFlights = flightDatabase.filter(flight => 
  flight.from === recommendation.fromCity &&
  flight.to === recommendation.toCity &&
  flight.date === recommendation.recommendedDate &&
  flight.timeCategory === recommendation.recommendedTime
);

// Sort by price (cheapest first)
matchedFlights.sort((a, b) => a.price - b.price);

// Take top 3 recommendations
const topRecommendations = matchedFlights.slice(0, 3);

return {
  tripId: recommendation.tripId,
  recommendation: recommendation,
  suggestedFlights: topRecommendations,
  alternativeDate: recommendation.recommendedDate, // Could add logic for backup dates
  message: `Found ${topRecommendations.length} flights matching team preferences`
};
